```class Solution {
    public boolean canPartitionKSubsets(int[] nums, int k) {
        int sum = calculateSum(nums);
        return canPartitionKSubsets(nums, sum, k);
    }

    private boolean canPartitionKSubsets(int[] nums, int sum, int k) {
        int n = nums.length;
        int[] dp = new int[k + 1];

        for (int i = 0; i <= k; i++) {
            dp[i] = Integer.MAX_VALUE;
        }

        dp[0] = 1;

        for (int i = 1; i <= n; i++) {
            for (int j = 0; j <= k; j++) {
                if (nums[i - 1] <= sum - i) {
                    dp[j] = Math.min(dp[j], dp[j - nums[i - 1] + 1];
                }
            }
        }

        return dp[k];
    }

    private int calculateSum(int[] nums) {
        int sum = 0;
        for (int num : nums) {
            sum += num;
        }
        return sum;
    }
}
